// Parse Zadarma inbound SMS or manual test payload
const body = $input.first().json.body || $input.first().json;
const from = (body.caller_id || body.from || body.sender || body.caller_number || body.number || '').replace(/[^+\d]/g, '');
const message = (body.message || body.text || body.content || body.sms_text || body.sms_body || '').trim();
const messageId = body.message_id || body.sms_id || body.id || $execution.id;

if (!from || !message) {
  return [{ json: { valid: false, reason: 'Missing from or message' } }];
}

if (!/^\+370\d{7,8}$/.test(from)) {
  return [{ json: { valid: false, reason: 'Invalid LT phone: ' + from } }];
}

return [{
  json: {
    valid: true,
    customerPhone: from,
    messageBody: message,
    messageId,
    receivedAt: new Date().toISOString()
  }
}];

// Load/init conversation from static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};

const phone = $input.first().json.customerPhone;
const now = new Date().toISOString();

if (!staticData.conversations[phone]) {
  staticData.conversations[phone] = {
    messages: [],
    startedAt: now,
    bookingStatus: 'none'
  };
}

const conv = staticData.conversations[phone];
conv.messages.push({
  role: 'customer',
  content: $input.first().json.messageBody,
  timestamp: now
});

// Keep last 20
if (conv.messages.length > 20) {
  conv.messages = conv.messages.slice(-20);
}

return [{
  json: {
    customerPhone: phone,
    messageBody: $input.first().json.messageBody,
    messageId: $input.first().json.messageId,
    conversationHistory: conv.messages,
    bookingStatus: conv.bookingStatus,
    isNewConversation: conv.messages.length === 1
  }
}];

// Normalize text: try quick booking intent extraction
// Pattern: DATA LAIKAS AUTO PROBLEMA
const msg = $input.first().json.messageBody;
const phone = $input.first().json.customerPhone;

// Try to extract structured booking from single message
// Examples: "2026-03-15 10:00 BMW 320d stabdžiai" or "kovo 15 10val audi a4 alyvos keitimas"
const normalized = msg
  .replace(/\s+/g, ' ')
  .trim();

return [{
  json: {
    ...$input.first().json,
    normalizedMessage: normalized
  }
}];

