// Parse AI response, detect booking intent
const aiRaw = $input.first().json;
let aiText = '';
if (aiRaw.choices && aiRaw.choices[0]) {
  aiText = aiRaw.choices[0].message?.content || '';
} else {
  aiText = JSON.stringify(aiRaw);
}
aiText = aiText.trim();

let bookingReady = false;
let bookingData = null;

try {
  const jsonMatch = aiText.match(/\{[\s\S]*"booking_ready"\s*:\s*true[\s\S]*\}/);
  if (jsonMatch) {
    bookingData = JSON.parse(jsonMatch[0]);
    bookingReady = true;
  }
} catch (e) { /* not JSON, conversation reply */ }

// Extract fields if booking ready
const extracted = bookingData ? {
  date: bookingData.preferred_date || '',
  time: bookingData.preferred_time || '',
  carInfo: bookingData.car_info || '',
  problem: bookingData.problem || bookingData.service_type || '',
  clientName: bookingData.client_name || ''
} : null;

const convData = $('Load Conversation').first().json;

// Save AI reply to conversation
const staticData = $getWorkflowStaticData('global');
if (staticData.conversations && staticData.conversations[convData.customerPhone]) {
  staticData.conversations[convData.customerPhone].messages.push({
    role: 'assistant',
    content: bookingReady ? 'Registracija patvirtinta!' : aiText,
    timestamp: new Date().toISOString()
  });
  if (bookingReady) {
    staticData.conversations[convData.customerPhone].bookingStatus = 'booked';
  }
}

return [{
  json: {
    bookingReady,
    replyText: bookingReady ? null : aiText,
    bookingData,
    extracted,
    customerPhone: convData.customerPhone,
    messageId: convData.messageId
  }
}];
